class Solution:
    def maxVowels(self, s: str, k: int) -> int:
        vowels = {'a', 'e', 'i', 'o', 'u'}
        max_vowels = current = sum(ch in vowels for ch in s[:k])
        for i in range(k, len(s)):
            current += (s[i] in vowels) - (s[i - k] in vowels)
            if current > max_vowels:
                max_vowels = current
        return max_vowels
